// scripts/check-bundle-size.ts — runs after `next build --turbopack`
import { readdirSync, statSync } from 'fs'
import { join } from 'path'

const CHUNK_DIR = join(process.cwd(), '.next/static/chunks')
const MAX_CHUNK_KB = 250

const chunks = readdirSync(CHUNK_DIR).filter(f => f.endsWith('.js'))
const violations: string[] = []

for (const chunk of chunks) {
  const sizeKB = statSync(join(CHUNK_DIR, chunk)).size / 1024
  if (sizeKB > MAX_CHUNK_KB)
    violations.push(`  ${chunk}: ${sizeKB.toFixed(1)}KB > ${MAX_CHUNK_KB}KB`)
}

if (violations.length) {
  console.error('Bundle budget exceeded:\n' + violations.join('\n'))
  process.exit(1)
}
console.log(`✓ All ${chunks.length} chunks within ${MAX_CHUNK_KB}KB budget.`)

